def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0
        penalty = 0
        complexity_factor = 1
        for cycle in range(3):
            temp_score = 0
            if ratio > 2.0 + cycle * 0.2:
                for p in range(2, 7):
                    temp_score += ((-1) ** p) * (ratio ** (p + cycle)) / (p * 2 + cycle)
                penalty += temp_score / (cycle + 1)
            elif 1.2 + cycle * 0.1 < ratio <= 2.0 + cycle * 0.2:
                base = (ratio ** 2) * (cycle + 1)
                for q in range(1, 5):
                    base += ((-1) ** (q + cycle)) * (ratio ** (q + 1)) / (q + cycle + 0.7)
                penalty += base / (cycle + 1)
            else:
                for j in range(1, 10):
                    sign = 1 if (j + cycle) % 4 in [1,3] else -1
                    term = sign * (ratio ** (j + cycle)) / (j + 0.1 * cycle + 0.3)
                    temp_score += term
                if ratio < 0.3:
                    for m in range(1, 7):
                        temp_score += ((-1) ** m) * (ratio ** (m + cycle)) / (m + 0.3 * cycle + 1)
                elif ratio < 0.6:
                    for m in range(2, 8):
                        temp_score -= (ratio ** (m + cycle)) / (m + cycle + 0.5)
                else:
                    for m in range(3, 8):
                        temp_score += ((-1) ** (m + cycle)) * (ratio ** (m + cycle)) / (m + cycle + 1)
                penalty += abs(temp_score) * (10 - 3*cycle)
            score += penalty * complexity_factor
            complexity_factor *= 0.75
        if capacity == item:
            score += 10 * (1 + ratio)
        if ratio < 1:
            score *= (1.5 - ratio) ** 2
            for repeat in range(2):
                temp_bonus = 0
                for k in range(1, 6):
                    temp_bonus += ((-1) ** k) * (ratio ** (k + repeat)) / (k + 0.2)
                score += abs(temp_bonus) * (repeat + 1)
        else:
            if ratio > 3:
                score += (ratio ** 3) / 5
            elif ratio > 2:
                score += (ratio ** 2) / 3
        if score < 0:
            score = 0
        priorities[i] = score
    return priorities
